{
  "sentences": [
    {
      "text": "這件上衣有沒有黑色的？",
      "pinyin": "Zhè jiàn shàngyī yǒu méiyǒu hēisè de?",
      "pinyin_numeric": "zhe4 jian4 shang4yi1 you3 mei2you3 hei1se4 de0",
      "translation_en": "Does this shirt come in black?",
      "translation_ko": "이 상의 검은색 있어요?"
    },
    {
      "text": "你們有沒有小號的褲子？",
      "pinyin": "Nǐmen yǒu méiyǒu xiǎohào de kùzi?",
      "pinyin_numeric": "ni3men0 you3 mei2you3 xiao3hao4 de0 ku4zi0",
      "translation_en": "Do you have small-size pants?",
      "translation_ko": "작은 사이즈 바지 있어요?"
    },
    {
      "text": "這件外套有沒有中號的？",
      "pinyin": "Zhè jiàn wàitào yǒu méiyǒu zhōnghào de?",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 you3 mei2you3 zhong1hao4 de0",
      "translation_en": "Does this jacket come in medium?",
      "translation_ko": "이 외투 중간 사이즈 있어요?"
    },
    {
      "text": "我想試穿這件藍色的裙子。",
      "pinyin": "Wǒ xiǎng shìchuān zhè jiàn lánsè de qúnzi.",
      "pinyin_numeric": "wo3 xiang3 shi4chuan1 zhe4 jian4 lan2se4 de0 qun2zi0",
      "translation_en": "I want to try on this blue skirt.",
      "translation_ko": "이 파란색 치마를 입어보고 싶어요."
    },
    {
      "text": "這雙鞋子有沒有白色的？",
      "pinyin": "Zhè shuāng xiézi yǒu méiyǒu báisè de?",
      "pinyin_numeric": "zhe4 shuang1 xie2zi0 you3 mei2you3 bai2se4 de0",
      "translation_en": "Do these shoes come in white?",
      "translation_ko": "이 신발 흰색 있어요?"
    },
    {
      "text": "你們有沒有大號的帽子？",
      "pinyin": "Nǐmen yǒu méiyǒu dàhào de màozi?",
      "pinyin_numeric": "ni3men0 you3 mei2you3 da4hao4 de0 mao4zi0",
      "translation_en": "Do you have large-size hats?",
      "translation_ko": "큰 사이즈 모자 있어요?"
    },
    {
      "text": "這件紅色的上衣有沒有小號的？",
      "pinyin": "Zhè jiàn hóngsè de shàngyī yǒu méiyǒu xiǎohào de?",
      "pinyin_numeric": "zhe4 jian4 hong2se4 de0 shang4yi1 you3 mei2you3 xiao3hao4 de0",
      "translation_en": "Does this red shirt come in small?",
      "translation_ko": "이 빨간색 상의 작은 사이즈 있어요?"
    },
    {
      "text": "我想試穿這件灰色的外套。",
      "pinyin": "Wǒ xiǎng shìchuān zhè jiàn huīsè de wàitào.",
      "pinyin_numeric": "wo3 xiang3 shi4chuan1 zhe4 jian4 hui1se4 de0 wai4tao4",
      "translation_en": "I want to try on this gray jacket.",
      "translation_ko": "이 회색 외투를 입어보고 싶어요."
    },
    {
      "text": "這條褲子有沒有綠色的？",
      "pinyin": "Zhè tiáo kùzi yǒu méiyǒu lǜsè de?",
      "pinyin_numeric": "zhe4 tiao2 ku4zi0 you3 mei2you3 lü4se4 de0",
      "translation_en": "Do these pants come in green?",
      "translation_ko": "이 바지 초록색 있어요?"
    },
    {
      "text": "你們有沒有中號的黃色上衣？",
      "pinyin": "Nǐmen yǒu méiyǒu zhōnghào de huángsè shàngyī?",
      "pinyin_numeric": "ni3men0 you3 mei2you3 zhong1hao4 de0 huang2se4 shang4yi1",
      "translation_en": "Do you have medium-size yellow shirts?",
      "translation_ko": "중간 사이즈 노란색 상의 있어요?"
    }
  ]
}
